const e={id:"A1",title:"Beginner – Découverte",subtitle:"Breakthrough",description:"Can understand and use familiar everyday expressions and very basic phrases. Can introduce themselves and others and can ask and answer questions about personal details.",chapters:[{id:"a1-ch1",title:"Salutations et Présentations",description:"Greetings, introductions, basic politeness - Module 1",concepts:[{id:"a1-ch1-c1",title:"Les salutations de base",description:"Basic greetings: bonjour, salut, bonsoir, au revoir, asking how someone is",grammarFocus:"Present tense: s'appeler; Subject pronouns; Formality (tu vs vous)",vocabularyTheme:"Greetings, farewells, politeness expressions",skills:{reading:{summary:"Read simple greeting dialogues and identify appropriate responses",exercises:[{id:"a1-ch1-c1-r1",title:"Identify the Greeting",type:"multiple-choice",prompt:"Read: 'It is 8 PM. You meet a colleague. What do you say?'",options:["Bonjour","Bonsoir","Bonne nuit","Salut"],correctAnswer:"Bonsoir",hint:"Bonsoir is used in the evening."},{id:"a1-ch1-c1-r2",title:"Dialogue Comprehension",type:"comprehension",prompt:"Read: 'Lucas: Salut! Sophie: Bonjour Lucas. Enchantée.' Who is Sophie meeting?"},{id:"a1-ch1-c1-r3",title:"Match Greetings",type:"match",prompt:"Match each French greeting to its English equivalent: Bonjour, Au revoir, Enchanté, À bientôt"}]},writing:{summary:"Write simple greetings and introductions using s'appeler",exercises:[{id:"a1-ch1-c1-w1",title:"Greeting Fill-In",type:"fill-blank",prompt:"Complete: '_____ (Hello), je m'appelle Pierre.'",correctAnswer:"Bonjour",hint:"The word means 'Hello'."},{id:"a1-ch1-c1-w2",title:"Formal vs Informal",type:"short-answer",prompt:"Write a formal greeting for your boss at 9 AM, and an informal one for a friend."},{id:"a1-ch1-c1-w3",title:"Greeting Dialogue",type:"prompt",prompt:"Write a short dialogue (4 lines) where you meet someone at a café, greet them, introduce yourself, and ask how they are."}]},listening:{summary:"Recognise spoken greetings and distinguish formal vs informal",exercises:[{id:"a1-ch1-c1-l1",title:"Listen and Respond",type:"multiple-choice",prompt:"Teacher says: 'Bonjour tout le monde! Je m'appelle Antoine. Je suis votre professeur de français... non, ne pleurez pas, c'est facile! Je suis très content d'être ici. Et vous, comment allez-vous? Fatigués? Stressés? Mais non, vous êtes formidables!' What is the teacher's name and how does he feel?",options:["Antoine, très content","Pierre, fatigué","Marc, stressé","Jean, triste"],correctAnswer:"Antoine, très content"},{id:"a1-ch1-c1-l2",title:"Formal or Informal?",type:"multiple-choice",prompt:"You hear colleagues at the office: 'Bonjour Monsieur Dupont. - Bonjour Madame Martin, comment allez-vous?' What level of formality is this?",options:["Formal","Informal","Very casual","Angry"],correctAnswer:"Formal"},{id:"a1-ch1-c1-l3",title:"Time of Day",type:"multiple-choice",prompt:"You hear someone say 'Bonne nuit' as you leave. What should you reply?",options:["Bonne nuit","Bonjour","Bonsoir","Salut"],correctAnswer:"Bonne nuit"}]},speaking:{summary:"Practise greeting, introducing yourself, and polite exchanges",exercises:[{id:"a1-ch1-c1-s1",title:"Meet & Greet",type:"roleplay",prompt:"Greet a new classmate: 'Bonjour, je m'appelle [name]. Enchanté(e).' Then ask 'Comment ça va?'"},{id:"a1-ch1-c1-s2",title:"Formal Introduction",type:"prompt",prompt:"Say aloud to an imaginary boss: 'Bonjour Monsieur/Madame, comment allez-vous? Je m'appelle [name]. Enchanté(e).'"},{id:"a1-ch1-c1-s3",title:"Leave-Taking",type:"roleplay",prompt:"Practise ending a conversation: 'Je dois y aller. Au revoir! À demain!' Use 'Bonne journée' if leaving a shop."}]}}},{id:"a1-ch1-c2",title:"Se présenter et demander le nom",description:"Introducing yourself and others, asking for names, the ça va loop",grammarFocus:"Verb: s'appeler (full conjugation); Question: Comment t'appelles-tu / vous appelez-vous",vocabularyTheme:"Personal identity, greetings, feelings (bien, mal, comme ci comme ça)",skills:{reading:{summary:"Read introductions and identify people and relationships",exercises:[{id:"a1-ch1-c2-r1",title:"Who is Who?",type:"comprehension",prompt:"Read: 'Voici Marie. Elle est française.' Who is being introduced and what is their nationality?"},{id:"a1-ch1-c2-r2",title:"Match Questions & Answers",type:"match",prompt:"Match 'Comment t'appelles-tu?' to 'Je m'appelle Sophie', 'Ça va?' to 'Oui, ça va bien'"},{id:"a1-ch1-c2-r3",title:"Short Story: Une nouvelle rencontre",type:"comprehension",prompt:"Read: 'Salut! Je m'appelle Thomas. J'ai vingt-cinq ans. Je suis étudiant à Paris. J'ai deux soeurs, elles s'appellent Alice et Julie. Aujourd'hui, je rencontre une nouvelle amie. Elle s'appelle Sofia. Elle est italienne et elle est très sympathique!' Question: Comment s'appelle la nouvelle amie de Thomas?"},{id:"a1-ch1-c2-r4",title:"Story Questions",type:"multiple-choice",prompt:"Pourquoi le chat Minou est-il gros?",options:["Parce qu'il mange le fromage du père","Parce qu'il dort beaucoup","Parce qu'il est vieux","Parce qu'il ne mange pas"],correctAnswer:"Parce qu'il mange le fromage du père"}]},writing:{summary:"Write self-introductions and fill in identity forms",exercises:[{id:"a1-ch1-c2-w1",title:"Your Profile",type:"prompt",prompt:"Write 3 sentences introducing yourself: name, how you are, and one greeting."},{id:"a1-ch1-c2-w2",title:"Conjugation Practice",type:"fill-blank",prompt:"Complete: Je m'appelle, tu t'_____, il s'_____, nous nous _____, vous vous _____, ils s'_____",correctAnswer:"appelles; appelle; appelons; appelez; appellent"},{id:"a1-ch1-c2-w3",title:"Formal Letter Opening",type:"prompt",prompt:"Write the first two lines of a formal letter introducing yourself to a French pen pal."}]},listening:{summary:"Understand spoken introductions and follow basic Q&A",exercises:[{id:"a1-ch1-c2-l1",title:"Listen for Names",type:"comprehension",prompt:"You hear: 'Je m'appelle Antoine. Je suis votre professeur de français.' What is the person's name and role?"},{id:"a1-ch1-c2-l2",title:"How Are They?",type:"multiple-choice",prompt:"You hear: 'Comment ça va? - Je vais très bien, merci.' How is the person?",options:["Very well","Not good","Tired","Hungry"],correctAnswer:"Very well"}]},speaking:{summary:"Introduce yourself and ask others for their name",exercises:[{id:"a1-ch1-c2-s1",title:"Meet Your Partner",type:"roleplay",prompt:"Ask a partner their name: 'Comment t'appelles-tu?' Respond: 'Je m'appelle... Enchanté(e)!'"},{id:"a1-ch1-c2-s2",title:"Interview",type:"prompt",prompt:"Ask three people (alternating tu/vous) their names and how they are doing."}]}}}]},{id:"a1-ch2",title:"Les Nombres, l'Heure et les Dates",description:"Numbers 0–100, telling time, days, months - Module 2",concepts:[{id:"a1-ch2-c1",title:"Les nombres 0–100",description:"Counting from zero to one hundred",grammarFocus:"Numbers 0-100; Quand interrogative; Prepositions: en, à, le for dates",vocabularyTheme:"Numbers, age, phone numbers, prices",skills:{reading:{summary:"Read and interpret numbers in various contexts",exercises:[{id:"a1-ch2-c1-r1",title:"Age Puzzle",type:"comprehension",prompt:"Read: 'J'ai vingt-sept ans.' How old is the person?"},{id:"a1-ch2-c1-r2",title:"Phone Number",type:"fill-blank",prompt:"Read this phone number: '06 12 34 56 78'. Write it out in French words.",correctAnswer:"zéro six douze trente-quatre cinquante-six soixante-dix-huit"},{id:"a1-ch2-c1-r3",title:"Math Challenge",type:"multiple-choice",prompt:"Read: 'dix + vingt = ?' What is the answer in French?",options:["trente","quarante","vingt-dix","trente-cinq"],correctAnswer:"trente"}]},writing:{summary:"Write numbers in French words",exercises:[{id:"a1-ch2-c1-w1",title:"Number Conversion",type:"fill-blank",prompt:"Write '35' in French: _____",correctAnswer:"trente-cinq"},{id:"a1-ch2-c1-w2",title:"Bigger Numbers",type:"fill-blank",prompt:"Write '72' in French: _____",correctAnswer:"soixante-douze"},{id:"a1-ch2-c1-w3",title:"Write Your Age",type:"prompt",prompt:"Write your age in a full French sentence: 'J'ai ____ ans.'"}]},listening:{summary:"Understand numbers spoken aloud",exercises:[{id:"a1-ch2-c1-l1",title:"Number Dictation",type:"dictation",prompt:"You hear: 'quarante-deux, soixante-dix-huit, quatre-vingt-treize'. Write the numbers.",hint:"quarante-deux=42, soixante-dix-huit=78, quatre-vingt-treize=93"},{id:"a1-ch2-c1-l2",title:"Train Announcement",type:"comprehension",prompt:"Station announcement: 'Attention s'il vous plaît. Le train numéro 452 à destination de Paris Gare du Nord partira à seize heures trente du quai numéro douze. Je répète: seize heures trente, quai douze. Attention, ce train est souvent en retard, c'est la France!' What is the train number, departure time, and platform?"},{id:"a1-ch2-c1-l3",title:"Price Check",type:"multiple-choice",prompt:"You hear: 'Ça fait quarante-cinq euros.' How much does it cost?",options:["35€","45€","55€","65€"],correctAnswer:"45€"}]},speaking:{summary:"Count, say numbers aloud, and state age",exercises:[{id:"a1-ch2-c1-s1",title:"Count to 30",type:"prompt",prompt:"Count from 1 to 30 in French out loud."},{id:"a1-ch2-c1-s2",title:"Say Your Age & Phone",type:"prompt",prompt:"Say 'J'ai [your age] ans' and spell your phone number in French."},{id:"a1-ch2-c1-s3",title:"The Number Game",type:"roleplay",prompt:"Ask a partner 'Quel âge as-tu?' and 'Quel est ton numéro de téléphone?' Answer in French."}]}}},{id:"a1-ch2-c2",title:"L'heure et le calendrier",description:"Telling time, days of the week, months, and dates",grammarFocus:"Il est + heure; Prepositions: à, en, le; 12h vs 24h clock",vocabularyTheme:"Time expressions, days, months, seasons",skills:{reading:{summary:"Read schedules, diaries, and calendar entries",exercises:[{id:"a1-ch2-c2-r1",title:"Daily Diary",type:"comprehension",prompt:"Read: 'Aujourd'hui, nous sommes le lundi 12 mai. Il est huit heures du matin. J'ai un rendez-vous à dix heures et quart.' What day is it?"},{id:"a1-ch2-c2-r2",title:"Train Timetable",type:"multiple-choice",prompt:"Read: 'Départ: 14h45. Quai numéro 7.' What time does the train depart?",options:["2:45 PM","4:45 PM","7:45 AM","12:45 PM"],correctAnswer:"2:45 PM"}]},writing:{summary:"Write dates and times in full French",exercises:[{id:"a1-ch2-c2-w1",title:"Today's Date",type:"prompt",prompt:"Write today's date in full French: 'Aujourd'hui, nous sommes le...'"},{id:"a1-ch2-c2-w2",title:"Time Writing",type:"fill-blank",prompt:"Write 8:15 in French: 'Il est _____'",correctAnswer:"huit heures et quart"}]},listening:{summary:"Understand times and dates spoken in announcements",exercises:[{id:"a1-ch2-c2-l1",title:"Time Dictation",type:"dictation",prompt:"You hear times: 'Il est sept heures moins le quart', 'Il est midi', 'Il est seize heures et demie'. Write each one in numbers."},{id:"a1-ch2-c2-l2",title:"Anniversary Date",type:"comprehension",prompt:"You hear: 'En juin, c'est mon anniversaire, le vingt-deux juin.' What is the date?"}]},speaking:{summary:"Tell time, say dates, and discuss schedules",exercises:[{id:"a1-ch2-c2-s1",title:"What Time Is It?",type:"prompt",prompt:"Say the current time in French. Use 'Il est... heures.'"},{id:"a1-ch2-c2-s2",title:"Weekly Schedule",type:"prompt",prompt:"Say your schedule: 'Le lundi, je travaille. Le samedi, je me repose.' Use at least 4 days."}]}}}]},{id:"a1-ch3",title:"La Famille et les Relations",description:"Family members, possessive adjectives, pets - Module 3",concepts:[{id:"a1-ch3-c1",title:"Les membres de la famille",description:"Identifying and describing family members",grammarFocus:"Verb: avoir (j'ai, tu as, il/elle a); Noun genders in family",vocabularyTheme:"Family members, marital status, pets",skills:{reading:{summary:"Read short family descriptions",exercises:[{id:"a1-ch3-c1-r1",title:"Family Tree",type:"comprehension",prompt:"Read: 'Mon père s'appelle Jean. Ma mère s'appelle Marie. J'ai un frère, il s'appelle Thomas.' How many siblings does the person have?"},{id:"a1-ch3-c1-r2",title:"Family Riddle",type:"multiple-choice",prompt:"Read: 'Jean est le frère de mon père.' Who is Jean?",options:["My grandfather","My uncle","My cousin","My brother"],correctAnswer:"My uncle"}]},writing:{summary:"Describe your family members",exercises:[{id:"a1-ch3-c1-w1",title:"My Family",type:"prompt",prompt:"Write 4 sentences about your family: who they are, their names, and one thing about each."},{id:"a1-ch3-c1-w2",title:"Avoir Conjugation",type:"fill-blank",prompt:"Complete: J'___ (have), tu ___ (have), il ___ (has), nous ___ (have), vous ___ (have), ils ___ (have)",correctAnswer:"ai; as; a; avons; avez; ont"}]},listening:{summary:"Understand spoken family descriptions",exercises:[{id:"a1-ch3-c1-l1",title:"Photo Description",type:"comprehension",prompt:"You hear: 'Sur cette photo, c'est ma famille. Voici mes parents, Robert et Catherine. Mon frère Paul est à gauche. Il a dix-neuf ans et il est très bruyant. Ma soeur Léa est à droite. Elle a vingt-quatre ans. Et le petit chien, c'est Snoopy! Snoopy est le membre le plus intelligent de la famille.' Name three family members mentioned."},{id:"a1-ch3-c1-l2",title:"Family Details",type:"multiple-choice",prompt:"You hear: 'Mon frère Paul a dix-neuf ans. Ma sœur Léa a vingt-quatre ans.' Who is older?",options:["Paul","Léa","Same age","Unknown"],correctAnswer:"Léa"}]},speaking:{summary:"Talk about your family",exercises:[{id:"a1-ch3-c1-s1",title:"Family Introduction",type:"prompt",prompt:"Introduce your family: 'Dans ma famille, il y a...' Use at least 4 people."},{id:"a1-ch3-c1-s2",title:"Pet Talk",type:"roleplay",prompt:"Tell a friend about your pet: 'J'ai un chat/Un chien. Il/Elle s'appelle...'"}]}}},{id:"a1-ch3-c2",title:"Les adjectifs possessifs",description:"Possessive adjectives: mon/ma/mes, ton/ta/tes, son/sa/ses",grammarFocus:"Possessive adjectives; Gender exceptions (mon amie)",vocabularyTheme:"Relationships, personal items, descriptions",skills:{reading:{summary:"Interpret possessive adjectives in context",exercises:[{id:"a1-ch3-c2-r1",title:"Whose is it?",type:"comprehension",prompt:"Read: 'C'est son frère.' Can you tell if it's 'his brother' or 'her brother'?"},{id:"a1-ch3-c2-r2",title:"Possessive Match",type:"match",prompt:"Match: 'mon livre' (my book), 'ta maison' (your house), 'ses parents' (his/her parents)"}]},writing:{summary:"Use possessive adjectives correctly",exercises:[{id:"a1-ch3-c2-w1",title:"Choose the Possessive",type:"fill-blank",prompt:"Complete: '___ (My) soeur est gentille. ___ (His) père est strict.'",correctAnswer:"Ma; Son"},{id:"a1-ch3-c2-w2",title:"The Vowel Rule",type:"fill-blank",prompt:"Complete: 'C'est _____ (my - f) amie.' (Remember the rule!)",correctAnswer:"mon"}]},listening:{summary:"Recognise possessive forms in spoken French",exercises:[{id:"a1-ch3-c2-l1",title:"Listen and Identify",type:"comprehension",prompt:"You hear: 'Mon père est médecin et ma mère est professeur.' What are their professions?"},{id:"a1-ch3-c2-l2",title:"Whose Pet?",type:"multiple-choice",prompt:"You hear: 'C'est son chat blanc.' Whose cat is it?",options:["My cat","Your cat","His or her cat","Our cat"],correctAnswer:"His or her cat"}]},speaking:{summary:"Practise using possessives",exercises:[{id:"a1-ch3-c2-s1",title:"Family Possessives",type:"roleplay",prompt:"Point to photos and say: 'C'est ma mère. Voici mon père. Ce sont mes frères.'"},{id:"a1-ch3-c2-s2",title:"Talk About Your Things",type:"prompt",prompt:"Show three objects and say whose they are: 'C'est mon téléphone. C'est ton livre. C'est son stylo.'"}]}}}]},{id:"a1-ch4",title:"Ma Maison et ma Routine",description:"Describing your home, rooms, and daily activities - Module 4",concepts:[{id:"a1-ch4-c1",title:"Les pièces de la maison",description:"House rooms, furniture, and prepositions of place",grammarFocus:"Il y a / il n'y a pas de; Prepositions: dans, sur, sous, devant, derrière",vocabularyTheme:"House, rooms, furniture, home items",skills:{reading:{summary:"Read descriptions of homes and room layouts",exercises:[{id:"a1-ch4-c1-r1",title:"Apartment Tour",type:"comprehension",prompt:"Read: 'J'habite dans une petite maison avec un jardin. Dans ma maison, il y a deux chambres, un grand salon et une cuisine moderne.' How many bedrooms?"},{id:"a1-ch4-c1-r2",title:"Where Is It?",type:"multiple-choice",prompt:"Read: 'Le chat dort sur le canapé.' Where is the cat?",options:["Under the sofa","On the sofa","Next to the sofa","Behind the sofa"],correctAnswer:"On the sofa"}]},writing:{summary:"Describe your home using il y a and prepositions",exercises:[{id:"a1-ch4-c1-w1",title:"My Dream Home",type:"prompt",prompt:"Describe your ideal home in 4 sentences. Use 'Dans ma maison, il y a...' Mention at least 3 rooms."},{id:"a1-ch4-c1-w2",title:"Preposition Practice",type:"fill-blank",prompt:"Complete: 'Le livre est _____ (on) la table. Le chat est _____ (under) le canapé.'",correctAnswer:"sur; sous"}]},listening:{summary:"Understand descriptions of room layouts",exercises:[{id:"a1-ch4-c1-l1",title:"Messy Room",type:"comprehension",prompt:"You hear: 'Dans ma chambre, il y a un lit, un bureau noir. Sous le lit, il y a mes chaussures!' Where are the shoes?"},{id:"a1-ch4-c1-l2",title:"House Tour",type:"comprehension",prompt:"You hear: 'La cuisine est à côté du salon. La salle de bains est en face de la chambre.' Which room is next to the living room?"}]},speaking:{summary:"Give a tour of your home",exercises:[{id:"a1-ch4-c1-s1",title:"Room Tour",type:"prompt",prompt:"Give a 1-minute tour of your home: 'Dans mon appartement/ma maison, il y a...'"},{id:"a1-ch4-c1-s2",title:"Where's the Cat?",type:"roleplay",prompt:"Describe where things are using prepositions of place."}]}}},{id:"a1-ch4-c2",title:"La routine quotidienne",description:"Daily routines and reflexive verbs",grammarFocus:"Reflexive verbs: se lever, se doucher, s'habiller, se coucher",vocabularyTheme:"Daily activities, morning routine, evening routine",skills:{reading:{summary:"Read daily routine descriptions",exercises:[{id:"a1-ch4-c2-r1",title:"Morning Routine",type:"comprehension",prompt:"Read: 'Je me réveille à six heures. Je me douche et je m'habille. Ensuite, je prends mon petit-déjeuner.' What does the person do after showering?"},{id:"a1-ch4-c2-r2",title:"Routine Order",type:"multiple-choice",prompt:"Read: 'Le matin, je me lève, je me douche, je prends le petit-déjeuner.' What comes first?",options:["Shower","Get up","Breakfast","Get dressed"],correctAnswer:"Get up"},{id:"a1-ch4-c2-r3",title:"Short Story: La journée de Marie",type:"comprehension",prompt:"Read: 'Marie habite dans un appartement à Lyon. Il pleut et il y a du vent. Marie déteste la pluie. Tous les jours, elle se lève à sept heures et quart. Elle se douche et elle se prépare. Elle est assez petite et elle a les cheveux blonds. Elle prend son café dans le salon, sur le canapé.' Question: Quel temps fait-il dans l'histoire?"}]},writing:{summary:"Write about your daily routine",exercises:[{id:"a1-ch4-c2-w1",title:"My Day",type:"prompt",prompt:"Write 5 sentences about your daily routine using reflexive verbs."},{id:"a1-ch4-c2-w2",title:"Reflexive Fill-In",type:"fill-blank",prompt:"Complete: 'Je ____ lève à 7h. Tu ____ lèves à 8h. Nous ____ lavons.'",correctAnswer:"me; te; nous"}]},listening:{summary:"Understand spoken descriptions of daily routines",exercises:[{id:"a1-ch4-c2-l1",title:"Listen to the Routine",type:"comprehension",prompt:"You hear: 'D'habitude, je me lève tôt, vers six heures et demie. C'est horrible. Je prends une douche et je m'habille. Je ne prends pas de petit-déjeuner à la maison car je n'ai pas le temps. J'achète un gros croissant et un café près du bureau à huit heures. C'est mon moment préféré de la journée.' What time does the person get up and what is their favorite moment?"},{id:"a1-ch4-c2-l2",title:"Missing Breakfast",type:"comprehension",prompt:"You hear: 'Je ne prends pas de petit-déjeuner à la maison car je n'ai pas le temps.' Why doesn't the person eat at home?"}]},speaking:{summary:"Talk about your daily schedule",exercises:[{id:"a1-ch4-c2-s1",title:"Walk Through Your Day",type:"prompt",prompt:"Describe your morning routine step by step. Use at least 3 reflexive verbs."},{id:"a1-ch4-c2-s2",title:"Compare Routines",type:"roleplay",prompt:"Ask a partner: 'À quelle heure est-ce que tu te lèves?'"}]}}}]},{id:"a1-ch5",title:"La Nourriture et le Restaurant",description:"Food, drinks, ordering at a restaurant - Module 5",concepts:[{id:"a1-ch5-c1",title:"Les aliments et les boissons",description:"Food vocabulary and partitive articles",grammarFocus:"Partitive articles (du, de la, de l', des); Negation: ne...pas de; Verb: manger",vocabularyTheme:"Food, drinks, groceries, meals",skills:{reading:{summary:"Read menus, recipes, and grocery lists",exercises:[{id:"a1-ch5-c1-r1",title:"Menu Reading",type:"comprehension",prompt:"Read: 'Entrée: salade verte. Plat principal: poulet avec des légumes. Dessert: tarte aux pommes.' What is the main course?"},{id:"a1-ch5-c1-r2",title:"Grocery List",type:"multiple-choice",prompt:"Read: 'Je veux du pain, de la confiture et des fruits.' What does the person NOT want?",options:["Bread","Jam","Fruit","Cheese"],correctAnswer:"Cheese"}]},writing:{summary:"Write using partitive articles",exercises:[{id:"a1-ch5-c1-w1",title:"Grocery List",type:"prompt",prompt:"Write a shopping list using 'Je dois acheter du/de la/de l'/des...' for at least 5 items."},{id:"a1-ch5-c1-w2",title:"Partitive Fill-In",type:"fill-blank",prompt:"Complete: 'Je mange _____ pain. Tu bois _____ eau. Elle achète _____ fruits.'",correctAnswer:"du; de l'; des"},{id:"a1-ch5-c1-w3",title:"The Negative Switch",type:"fill-blank",prompt:"Transform to negative: 'Je mange du pain' -> 'Je ne mange pas _____ pain.'",correctAnswer:"de"}]},listening:{summary:"Understand food orders and market conversations",exercises:[{id:"a1-ch5-c1-l1",title:"Market Shopping",type:"comprehension",prompt:"At the market: 'Bonjour Monsieur, je voudrais deux kilos d'oranges et un morceau de fromage, s'il vous plaît. Ça fait combien? - Dix euros, Madame.' What does the person buy and what is the total price?"},{id:"a1-ch5-c1-l2",title:"Morning Drinks",type:"comprehension",prompt:"You hear: 'Je bois du café le matin. Ma soeur boit du thé.' What does the speaker drink?"}]},speaking:{summary:"Talk about food and quantities",exercises:[{id:"a1-ch5-c1-s1",title:"What's in Your Fridge?",type:"prompt",prompt:"Say what you have: 'Dans mon frigo, il y a du lait, de la salade, des oeufs...'"},{id:"a1-ch5-c1-s2",title:"Likes & Dislikes",type:"roleplay",prompt:"Tell a friend: 'J'aime... Je n'aime pas... Je préfère...'"}]}}},{id:"a1-ch5-c2",title:"Commander au restaurant",description:"Ordering meals, politeness formulas, asking for the bill",grammarFocus:"Verb: vouloir (je voudrais), boire; Politeness: conditionnel",vocabularyTheme:"Restaurant, menu, bill, service",skills:{reading:{summary:"Read restaurant dialogues",exercises:[{id:"a1-ch5-c2-r1",title:"Restaurant Dialogue",type:"comprehension",prompt:"Read: 'Ce soir, je vais au restaurant. Je voudrais une salade. Comme plat principal, je prends du poulet.' What starter does the person order?"},{id:"a1-ch5-c2-r2",title:"Politeness Test",type:"multiple-choice",prompt:"Which is more polite: 'Je voudrais un café' or 'Je veux un café'?",options:["Je voudrais","Je veux","Both are fine","Neither"],correctAnswer:"Je voudrais"}]},writing:{summary:"Write restaurant dialogues",exercises:[{id:"a1-ch5-c2-w1",title:"Order at a Café",type:"prompt",prompt:"Write a short dialogue ordering a coffee and croissant. Include greeting, order, thanks."},{id:"a1-ch5-c2-w2",title:"Ask for the Bill",type:"prompt",prompt:"Write 3 polite ways to ask for the bill."}]},listening:{summary:"Understand restaurant conversations",exercises:[{id:"a1-ch5-c2-l1",title:"Placing an Order",type:"comprehension",prompt:"You hear: 'Je voudrais un café noir et un croissant.' What is the order?"},{id:"a1-ch5-c2-l2",title:"Steak Doneness",type:"multiple-choice",prompt:"You hear: 'Quelle cuisson? - Saignant.' How do they want the steak?",options:["Rare","Medium","Well-done","Blue"],correctAnswer:"Rare"}]},speaking:{summary:"Roleplay ordering at a restaurant",exercises:[{id:"a1-ch5-c2-s1",title:"At the Restaurant",type:"roleplay",prompt:"Roleplay: greet, order a starter, main course, drink, and ask for the bill."},{id:"a1-ch5-c2-s2",title:"Polite Customer",type:"prompt",prompt:"Practice: 'Bonjour, une table pour deux. Je voudrais voir la carte. L'addition, s'il vous plaît.'"}]}}}]},{id:"a1-ch6",title:"Les Achats et les Vêtements",description:"Clothes, colors, shopping, prices - Module 6",concepts:[{id:"a1-ch6-c1",title:"Les vêtements et les couleurs",description:"Clothing items, colors, adjective agreement",grammarFocus:"Adjective agreement; Verb: mettre; Irregular colors: marron, orange",vocabularyTheme:"Clothes, accessories, colors, sizes",skills:{reading:{summary:"Read clothing descriptions",exercises:[{id:"a1-ch6-c1-r1",title:"Shopping Description",type:"comprehension",prompt:"Read: 'Cette veste rouge est très belle, mais elle coûte quatre-vingts euros.' What color is the jacket and how much?"},{id:"a1-ch6-c1-r2",title:"Color Agreement",type:"multiple-choice",prompt:"Read: 'Une robe _____ (blanc).' Choose the correct form.",options:["blanc","blanche","blanches","blancs"],correctAnswer:"blanche"},{id:"a1-ch6-c1-r3",title:"Short Story: Au marché de Provence",type:"comprehension",prompt:"Read: 'C'est samedi matin. Lucas va au marché à pied. Il porte un tee-shirt bleu et un short gris. Au marché, il y a beaucoup de gens. Lucas achète du fromage, de la baguette et des fraises. Il voit une belle écharpe jaune pour sa grand-mère.' Question: Comment Lucas va-t-il au marché?"},{id:"a1-ch6-c1-r4",title:"Story Details",type:"multiple-choice",prompt:"Combien coûte l'écharpe?",options:["Dix euros","Quinze euros","Vingt euros","Cinq euros"],correctAnswer:"Quinze euros"}]},writing:{summary:"Describe outfits using colors",exercises:[{id:"a1-ch6-c1-w1",title:"My Outfit",type:"prompt",prompt:"Describe what you're wearing today. Use colors and demonstrative adjectives."},{id:"a1-ch6-c1-w2",title:"Color Fill-In",type:"fill-blank",prompt:"Complete: 'Une chemise _____ (white). Des chaussures _____ (blue).'",correctAnswer:"blanche; bleues"},{id:"a1-ch6-c1-w3",title:"The Rebel Colors",type:"fill-blank",prompt:"Complete: 'Des chaussures _____ (marron). Des sacs _____ (orange).'",correctAnswer:"marron; orange"}]},listening:{summary:"Understand clothing conversations",exercises:[{id:"a1-ch6-c1-l1",title:"Fashion Talk",type:"comprehension",prompt:"You hear: 'Regarde cette veste, elle est super! - Oui, mais elle est un peu chère, non? - Elle coûte soixante-neuf euros. C'est raisonnable pour du cuir. - Tu as raison. Je vais l'essayer en taille M. Oh non, c'est trop petit. Je suis trop musclé pour cette veste!' What is the price and why doesn't size M fit?"},{id:"a1-ch6-c1-l2",title:"Size Problem",type:"multiple-choice",prompt:"Pourquoi la taille M ne va pas?",options:["Trop grand","Trop petit","Trop cher","Mauvaise couleur"],correctAnswer:"Trop petit"}]},speaking:{summary:"Describe clothes and fashion",exercises:[{id:"a1-ch6-c1-s1",title:"Fashion Show",type:"prompt",prompt:"Describe an outfit you love: 'Aujourd'hui, je porte...'"},{id:"a1-ch6-c1-s2",title:"Style Critique",type:"roleplay",prompt:"Comment on a friend's outfit: 'J'adore cette chemise!'"}]}}},{id:"a1-ch6-c2",title:"Les achats",description:"Shopping dialogues, asking prices, sizes",grammarFocus:"Demonstrative adjectives; Verb: acheter, payer; Combien interrogative",vocabularyTheme:"Shops, prices, sizes (taille vs pointure), payment",skills:{reading:{summary:"Read price tags and shop signs",exercises:[{id:"a1-ch6-c2-r1",title:"Shop Signs",type:"comprehension",prompt:"Read: 'Boulangerie - Ouvert du lundi au samedi.' When is the bakery closed?"},{id:"a1-ch6-c2-r2",title:"Demonstrative Match",type:"match",prompt:"Match: 'ce pull', 'cette robe', 'ces chaussures', 'cet homme'"}]},writing:{summary:"Write shopping dialogues",exercises:[{id:"a1-ch6-c2-w1",title:"Shopping Dialogue",type:"prompt",prompt:"Write a dialogue: ask for an item, ask the price, try on, and buy."},{id:"a1-ch6-c2-w2",title:"Demonstrative Fill-In",type:"fill-blank",prompt:"Complete: '_____ (This) jupe est trop courte. _____ (These) chaussures sont trop chères.'",correctAnswer:"Cette; Ces"},{id:"a1-ch6-c2-w3",title:"Taille vs Pointure",type:"multiple-choice",prompt:"Buying shoes - do you ask for 'taille' or 'pointure'?",options:["Taille","Pointure","Numéro","Pied"],correctAnswer:"Pointure"}]},listening:{summary:"Understand prices and payment conversations",exercises:[{id:"a1-ch6-c2-l1",title:"Checkout",type:"comprehension",prompt:"You hear: 'Ça fait 45 euros. Vous payez comment? - Par carte.' How does the customer pay?"},{id:"a1-ch6-c2-l2",title:"Adding Items",type:"comprehension",prompt:"You hear: 'Et ce sac aussi. Total: 50 euros.' What is the total?"}]},speaking:{summary:"Practise shopping conversations",exercises:[{id:"a1-ch6-c2-s1",title:"At the Boutique",type:"roleplay",prompt:"Buy a shirt: 'Puis-je essayer?', 'Combien ça coûte?'"},{id:"a1-ch6-c2-s2",title:"Market Stall",type:"prompt",prompt:"Ask for 3 items, ask prices, say how you'll pay."}]}}}]},{id:"a1-ch7",title:"Les Loisirs et les Intérêts",description:"Hobbies, sports, music, expressing likes - Module 7",concepts:[{id:"a1-ch7-c1",title:"Les activités de loisirs",description:"Leisure activities and adverbs of frequency",grammarFocus:"Verb: faire; Adverbs of frequency; Jouer à (sports) vs Jouer de (instruments)",vocabularyTheme:"Hobbies, sports, musical instruments, frequency",skills:{reading:{summary:"Read about people's hobbies",exercises:[{id:"a1-ch7-c1-r1",title:"Weekend Activities",type:"comprehension",prompt:"Read: 'Tous les samedis, je joue au tennis. Le dimanche, je fais du vélo.' What does the person do on Saturdays?"},{id:"a1-ch7-c1-r2",title:"Hobby Match",type:"match",prompt:"Match: 'faire du vélo', 'jouer au tennis', 'jouer de la guitare'"},{id:"a1-ch7-c1-r3",title:"Short Story: Les passions de Théo",type:"comprehension",prompt:"Read: 'Théo adore la musique et il joue souvent de la guitare. Le week-end, il fait du vélo avec son frère. Mais aujourd'hui, Théo est triste. Pourquoi? Parce qu'il a mal à la jambe! Il tombe de son vélo dimanche. Le médecin dit: Tu dois rester au lit et te reposer.' Question: Pourquoi Théo est-il triste?"},{id:"a1-ch7-c1-r4",title:"Story Health",type:"multiple-choice",prompt:"Quel est le conseil du médecin?",options:["Faire du sport","Rester au lit et se reposer","Manger du gâteau","Aller à la plage"],correctAnswer:"Rester au lit et se reposer"}]},writing:{summary:"Write about your hobbies",exercises:[{id:"a1-ch7-c1-w1",title:"My Hobbies",type:"prompt",prompt:"Write a paragraph about your hobbies. Use faire and jouer."},{id:"a1-ch7-c1-w2",title:"Faire vs Jouer",type:"fill-blank",prompt:"Complete: 'Je _____ du tennis. Je _____ de la guitare. Je _____ de la natation.'",correctAnswer:"joue; joue; fais"},{id:"a1-ch7-c1-w3",title:"Frequency",type:"prompt",prompt:"Write what you always, often, sometimes, never do."}]},listening:{summary:"Understand spoken hobby descriptions",exercises:[{id:"a1-ch7-c1-l1",title:"Weekend Plans",type:"comprehension",prompt:"Dialogue: 'Qu'est-ce que tu fais ce week-end? - Samedi, je joue au tennis. Dimanche, je vais au cinéma pour voir un film d'horreur. Et toi? - Moi, je reste à la maison. Je déteste le sport et j'ai peur des films d'horreur. Je vais juste dormir et manger.' What does the first person do on Sunday?"},{id:"a1-ch7-c1-l2",title:"Extreme Tastes",type:"comprehension",prompt:"You hear: 'Je déteste le froid, j'adore voyager dans les pays chauds.' What does the person love?"}]},speaking:{summary:"Discuss hobbies and interests",exercises:[{id:"a1-ch7-c1-s1",title:"Weekly Schedule",type:"prompt",prompt:"Describe a typical week with at least 3 hobbies."},{id:"a1-ch7-c1-s2",title:"Hidden Talent",type:"roleplay",prompt:"Tell a partner about your hidden talent: 'Mon talent caché est...'"}]}}},{id:"a1-ch7-c2",title:"Les sports et les instruments",description:"Sports and music vocabulary, faire vs jouer distinction",grammarFocus:"Jouer à (sports) vs Jouer de (instruments); Faire + partitive",vocabularyTheme:"Team sports, individual sports, musical instruments",skills:{reading:{summary:"Read about sports and music",exercises:[{id:"a1-ch7-c2-r1",title:"Sports Fan",type:"comprehension",prompt:"Read: 'Je joue au football tous les samedis. Je fais aussi de la natation.' What sport on Saturdays?"},{id:"a1-ch7-c2-r2",title:"Faire + Activity",type:"multiple-choice",prompt:"Read: 'Ma passion, c'est la danse! Je fais de la danse.' What verb is used?",options:["Jouer","Faire","Aller","Prendre"],correctAnswer:"Faire"}]},writing:{summary:"Write about sports and music",exercises:[{id:"a1-ch7-c2-w1",title:"Sports & Music",type:"prompt",prompt:"Write 4 sentences: 2 about sports (jouer à) and 2 about activities (faire de)."},{id:"a1-ch7-c2-w2",title:"Jouer Fill-In",type:"fill-blank",prompt:"Complete: 'Je joue _____ basket. Tu joues _____ guitare.'",correctAnswer:"au; de la"}]},listening:{summary:"Understand sports and music discussions",exercises:[{id:"a1-ch7-c2-l1",title:"Hobbies Discussion",type:"comprehension",prompt:"You hear: 'J'adore jouer du piano. Et toi? - Moi, je joue au basket.' What does the first person play?"},{id:"a1-ch7-c2-l2",title:"Frequency Quiz",type:"multiple-choice",prompt:"You hear: 'Je joue souvent au tennis, mais jamais de yoga.' What do they never do?",options:["Tennis","Yoga","Both","Neither"],correctAnswer:"Yoga"}]},speaking:{summary:"Discuss sports and musical interests",exercises:[{id:"a1-ch7-c2-s1",title:"Sport Interview",type:"roleplay",prompt:"Ask: 'Tu fais du sport? Tu joues d'un instrument?'"},{id:"a1-ch7-c2-s2",title:"My Passion",type:"prompt",prompt:"Talk for 1 minute about your favorite hobby."}]}}}]},{id:"a1-ch8",title:"La Ville et les Transports",description:"City places, transportation, directions - Module 8",concepts:[{id:"a1-ch8-c1",title:"Les lieux de la ville",description:"Public places and using à with contractions",grammarFocus:"Contractions: au, à la, à l', aux; Verb: aller; Où interrogative",vocabularyTheme:"City places, shops, services",skills:{reading:{summary:"Read city descriptions and signs",exercises:[{id:"a1-ch8-c1-r1",title:"City Guide",type:"comprehension",prompt:"Read: 'La poste est à côté de la boulangerie. La gare est en face du parc.' Where is the train station?"},{id:"a1-ch8-c1-r2",title:"Location Logic",type:"multiple-choice",prompt:"Read: 'Le musée est à droite de la banque.' Where is the museum?",options:["Left of bank","Right of bank","Behind bank","In front"],correctAnswer:"Right of bank"}]},writing:{summary:"Write about places in a city",exercises:[{id:"a1-ch8-c1-w1",title:"My Neighborhood",type:"prompt",prompt:"Describe your neighborhood: 'Dans mon quartier, il y a...' Mention shops and parks."},{id:"a1-ch8-c1-w2",title:"Contraction Fill-In",type:"fill-blank",prompt:"Complete: 'Je vais _____ musée. Nous allons _____ poste.'",correctAnswer:"au; à la"}]},listening:{summary:"Understand location descriptions",exercises:[{id:"a1-ch8-c1-l1",title:"Lost Tourist",type:"comprehension",prompt:"Tourist: 'Pardon madame, pour aller au Musée du Louvre, s'il vous plaît?' - Local: 'Oh, c'est loin! Vous devez prendre le métro, ligne un. - C'est direct? - Oui, c'est direct. Mais attention aux pickpockets, gardez votre sac fermé!' Which metro line should they take and what warning is given?"},{id:"a1-ch8-c1-l2",title:"Metro Announcement",type:"comprehension",prompt:"You hear: 'Prochaine station: Hôtel de Ville. Correspondance avec la ligne un. Attention à la marche en descendant du train.' What is the station name and which line can you connect to?"}]},speaking:{summary:"Ask for and give locations",exercises:[{id:"a1-ch8-c1-s1",title:"Find the Bakery",type:"roleplay",prompt:"Ask: 'Pardon, où est la boulangerie?'"},{id:"a1-ch8-c1-s2",title:"Getting Around",type:"prompt",prompt:"Say how you get to places using en vs à for transport."}]}}},{id:"a1-ch8-c2",title:"Les directions et les transports",description:"Giving directions, imperative mood, transport vocabulary",grammarFocus:"Imperative: tournez, prenez, allez; En vs à for transport",vocabularyTheme:"Directions, transport modes, maps",skills:{reading:{summary:"Read and follow directions",exercises:[{id:"a1-ch8-c2-r1",title:"Find the Way",type:"comprehension",prompt:"Read: 'Continuez tout droit, tournez à droite. La gare est en face du parc.' What is the second step?"},{id:"a1-ch8-c2-r2",title:"Transport Choice",type:"multiple-choice",prompt:"Read: 'Je vais au parc _____ vélo. Je vais à Paris _____ train.'",options:["à, en","en, à","à, à","en, en"],correctAnswer:"à, en"}]},writing:{summary:"Write clear directions",exercises:[{id:"a1-ch8-c2-w1",title:"Give Directions",type:"prompt",prompt:"Write directions from your house to a bus stop using imperative forms."},{id:"a1-ch8-c2-w2",title:"Imperative Fill-In",type:"fill-blank",prompt:"Complete: '_____ (Go) tout droit. _____ (Turn) à gauche.'",correctAnswer:"Allez; Tournez"}]},listening:{summary:"Understand transport announcements",exercises:[{id:"a1-ch8-c2-l1",title:"Train Announcement",type:"comprehension",prompt:"You hear: 'Le train pour Lyon part à quatorze heures, voie trois.' Time and platform?"},{id:"a1-ch8-c2-l2",title:"Direction Check",type:"comprehension",prompt:"You hear: 'Continuez tout droit, tournez à gauche après la boulangerie.' Where to turn?"}]},speaking:{summary:"Give directions and discuss transport",exercises:[{id:"a1-ch8-c2-s1",title:"Tour Guide",type:"roleplay",prompt:"Give directions from the station to the square using imperative forms."},{id:"a1-ch8-c2-s2",title:"How You Travel",type:"prompt",prompt:"Explain your commute: 'Pour aller au travail, je prends le bus.'"}]}}}]},{id:"a1-ch9",title:"La Météo et le Portrait Physique",description:"Weather, physical descriptions, personality - Module 9",concepts:[{id:"a1-ch9-c1",title:"Le portrait physique",description:"Describing appearance and personality",grammarFocus:"Adjective agreement; Être vs Avoir; Beau/belle, vieux/vieille",vocabularyTheme:"Physical appearance, personality traits",skills:{reading:{summary:"Read physical descriptions",exercises:[{id:"a1-ch9-c1-r1",title:"Who Is This?",type:"comprehension",prompt:"Read: 'Maxime est grand et a les cheveux bruns bouclés. Il est sympathique et drôle.' What hair does Maxime have?"},{id:"a1-ch9-c1-r2",title:"Irregular Adjectives",type:"multiple-choice",prompt:"Read: 'C'est un _____ garçon. C'est une _____ fille.'",options:["beau, belle","belle, beau","beaux, belles","bel, belle"],correctAnswer:"beau, belle"}]},writing:{summary:"Write physical descriptions",exercises:[{id:"a1-ch9-c1-w1",title:"Missing Person",type:"prompt",prompt:"Write a report describing a friend: height, hair, eyes, clothing."},{id:"a1-ch9-c1-w2",title:"Adjective Agreement",type:"fill-blank",prompt:"Correct: 'Une femme (sérieux)' -> _____",correctAnswer:"sérieuse"}]},listening:{summary:"Understand spoken descriptions",exercises:[{id:"a1-ch9-c1-l1",title:"Roommate Description",type:"comprehension",prompt:"You hear: 'Mon nouveau colocataire s'appelle Bruno. Il est très grand et il a une barbe énorme. Il ressemble à un pirate! Il est très sympa mais il parle beaucoup. Aujourd'hui, il fait très chaud, alors Bruno porte un chapeau de soleil ridicule.' What does Bruno look like and why is he wearing a hat?"},{id:"a1-ch9-c1-l2",title:"Appearance Details",type:"multiple-choice",prompt:"You hear: 'Paul est grand, cheveux bruns, yeux bleus.' What eye color?",options:["Brown","Blue","Green","Black"],correctAnswer:"Blue"}]},speaking:{summary:"Describe people's appearance",exercises:[{id:"a1-ch9-c1-s1",title:"Describe Your Best Friend",type:"prompt",prompt:"Describe your best friend using 5+ adjectives."},{id:"a1-ch9-c1-s2",title:"Guess Who?",type:"roleplay",prompt:"Describe a famous person. Partner must guess."}]}}},{id:"a1-ch9-c2",title:"La météo",description:"Weather expressions and seasons",grammarFocus:"Faire + weather; Il y a du soleil/vent; Quel temps fait-il?",vocabularyTheme:"Weather, seasons, temperature",skills:{reading:{summary:"Read weather descriptions",exercises:[{id:"a1-ch9-c2-r1",title:"Weather Report",type:"comprehension",prompt:"Read: 'Aujourd'hui, il fait très beau à Nice. Il y a du soleil et il fait chaud.' What's the weather?"},{id:"a1-ch9-c2-r2",title:"Seasons Match",type:"match",prompt:"Match: 'Il neige' (winter), 'Il fait chaud' (summer)"}]},writing:{summary:"Write about weather",exercises:[{id:"a1-ch9-c2-w1",title:"Today's Weather",type:"prompt",prompt:"Describe today's weather using 3-4 expressions."},{id:"a1-ch9-c2-w2",title:"Weather Fill-In",type:"fill-blank",prompt:"Complete: 'Il _____ beau. Il _____ du soleil.'",correctAnswer:"fait; y a"}]},listening:{summary:"Understand weather forecasts",exercises:[{id:"a1-ch9-c2-l1",title:"Forecast",type:"comprehension",prompt:"You hear: 'Demain, il va pleuvoir. Il fera froid avec du vent.' What weather?"},{id:"a1-ch9-c2-l2",title:"Preferences",type:"comprehension",prompt:"You hear: 'Je préfère le soleil et la chaleur.' What does the person prefer?"}]},speaking:{summary:"Talk about weather",exercises:[{id:"a1-ch9-c2-s1",title:"Weather Report",type:"prompt",prompt:"Present a short weather forecast for your city."},{id:"a1-ch9-c2-s2",title:"Favorite Season",type:"prompt",prompt:"Say which season you prefer and why."}]}}}]},{id:"a1-ch10",title:"La Santé et le Corps Humain",description:"Body parts, expressing pain, health advice - Module 10",concepts:[{id:"a1-ch10-c1",title:"Les parties du corps",description:"Naming body parts and expressing pain",grammarFocus:"J'ai mal à + article; Verb: avoir mal; Body part genders",vocabularyTheme:"Body parts, symptoms, pain expressions",skills:{reading:{summary:"Read about symptoms",exercises:[{id:"a1-ch10-c1-r1",title:"Doctor Visit",type:"comprehension",prompt:"Read: 'J'ai mal à la gorge et j'ai de la fièvre. Je pense que j'ai un rhume.' What are the symptoms?"},{id:"a1-ch10-c1-r2",title:"Anatomy Match",type:"match",prompt:"Match: 'la tête' (head), 'le dos' (back), 'les dents' (teeth)"}]},writing:{summary:"Write about symptoms",exercises:[{id:"a1-ch10-c1-w1",title:"At the Doctor",type:"prompt",prompt:"Write a dialogue: tell the doctor what hurts using 'J'ai mal au/à la/aux...'"},{id:"a1-ch10-c1-w2",title:"Pain Expression",type:"fill-blank",prompt:"Complete: 'J'ai mal _____ (to the) dos. Il a mal _____ (to the) tête. Elle a mal _____ (to the) dents.'",correctAnswer:"au; à la; aux"},{id:"a1-ch10-c1-w3",title:"Calling In Sick",type:"prompt",prompt:"Write a sick day message: mention 2 body parts and 1 doctor's instruction."}]},listening:{summary:"Understand health conversations",exercises:[{id:"a1-ch10-c1-l1",title:"Medical Appointment",type:"comprehension",prompt:"Phone call: 'Cabinet médical, j'écoute. - Bonjour, je voudrais un rendez-vous pour mon fils. Il a très mal aux oreilles depuis ce matin. - Est-ce qu'il a de la fièvre? - Oui, un peu. Trente-huit cinq. - D'accord, venez à seize heures trente.' Who needs the appointment, what are their symptoms, and what is the temperature?"},{id:"a1-ch10-c1-l2",title:"Symptoms Check",type:"comprehension",prompt:"You hear: 'J'ai mal à la tête et j'ai de la fièvre.' What symptoms?"}]},speaking:{summary:"Describe symptoms",exercises:[{id:"a1-ch10-c1-s1",title:"At the Pharmacy",type:"roleplay",prompt:"Explain symptoms: 'Bonjour, j'ai un rhume et j'ai mal à la gorge.'"},{id:"a1-ch10-c1-s2",title:"Body Parts Quiz",type:"prompt",prompt:"Point and name 8 body parts in French."}]}}},{id:"a1-ch10-c2",title:"Les soins de santé",description:"Health advice, pourquoi/parce que, devoir",grammarFocus:"Verb: devoir; Pourquoi/Parce que; Health advice expressions",vocabularyTheme:"Health, medicine, doctor, pharmacy",skills:{reading:{summary:"Read health advice",exercises:[{id:"a1-ch10-c2-r1",title:"Doctor's Advice",type:"comprehension",prompt:"Read: 'Le médecin dit: Tu dois rester au lit et te reposer.' What's the advice?"},{id:"a1-ch10-c2-r2",title:"Health Poster",type:"multiple-choice",prompt:"Read: 'Mangez 5 fruits et légumes par jour.' How many?",options:["3","5","7","10"],correctAnswer:"5"}]},writing:{summary:"Write health advice",exercises:[{id:"a1-ch10-c2-w1",title:"Health Advice",type:"prompt",prompt:"Write 3 pieces of advice using 'Tu dois...' or 'Vous devez...'"},{id:"a1-ch10-c2-w2",title:"Pourquoi/Parce que",type:"fill-blank",prompt:"Complete: '_____ (Why) es-tu fatigué? - _____ (Because) je travaille.'",correctAnswer:"Pourquoi; Parce que"}]},listening:{summary:"Understand health advice",exercises:[{id:"a1-ch10-c2-l1",title:"Appointment Booking",type:"comprehension",prompt:"You hear: 'Est-ce qu'il a de la fièvre? - Oui, 38.5. - Venez à 16h30.' What is the fever?"},{id:"a1-ch10-c2-l2",title:"Medicine Advice",type:"comprehension",prompt:"You hear: 'Prenez ce médicament et ne mangez plus de gâteau!' What two pieces of advice?"}]},speaking:{summary:"Give and receive health advice",exercises:[{id:"a1-ch10-c2-s1",title:"You Should...",type:"roleplay",prompt:"Give advice: 'Tu dois dormir. Tu dois boire de l'eau.'"},{id:"a1-ch10-c2-s2",title:"Explaining Illness",type:"prompt",prompt:"Explain why you missed class: 'Pourquoi tu n'es pas venu? - Parce que j'étais malade.'"}]}}}]}]},t={id:"A2",title:"Elementary – Progrès",subtitle:"Waystage",description:"Can understand sentences and frequently used expressions. Can communicate in simple and routine tasks requiring a simple and direct exchange of information.",chapters:[{id:"a2-ch1",title:"Voyages et Vacances",description:"Travel, holidays, describing past experiences",concepts:[{id:"a2-ch1-c1",title:"Les voyages en train et en avion",description:"Booking tickets, navigating airports and train stations",grammarFocus:"Passé composé with avoir; Irregular past participles",vocabularyTheme:"Travel, tickets, stations, airports",skills:{reading:{summary:"Read travel schedules and tickets",exercises:[{id:"a2-ch1-c1-r1",title:"Train Schedule",type:"comprehension",prompt:"Read: 'TGV Paris-Lyon: Départ 14h15, Arrivée 16h30, Voie 7, Train 6941.' How long is the journey?",hint:"14h15 to 16h30 is 2h15"},{id:"a2-ch1-c1-r2",title:"E-ticket Details",type:"multiple-choice",prompt:"Read: 'Passager: Marie Dupont. Vol AF1234. Paris CDG – Nice. Embarquement: Porte B24, 10h45.' What is the flight number?",options:["AF1234","CDG","B24","6941"],correctAnswer:"AF1234"}]},writing:{summary:"Write about past travels",exercises:[{id:"a2-ch1-c1-w1",title:"My Last Trip",type:"prompt",prompt:"Write 5 sentences about your last trip using passé composé: où tu es allé(e), comment, avec qui, ce que tu as visité."},{id:"a2-ch1-c1-w2",title:"Past Participles",type:"fill-blank",prompt:"Complete in passé composé: 'Hier, je _____ (aller) au musée. Nous _____ (visiter) la tour Eiffel.'",correctAnswer:"suis allé; avons visité"}]},listening:{summary:"Understand travel announcements",exercises:[{id:"a2-ch1-c1-l1",title:"Airport Announcement",type:"comprehension",prompt:"You hear: 'Le vol AF1234 à destination de Nice est annoncé. Embarquement immédiat à la porte B24.' Where is the flight going?"},{id:"a2-ch1-c1-l2",title:"Delay Notice",type:"multiple-choice",prompt:"You hear: 'Le TGV 6941 à destination de Lyon aura 20 minutes de retard.' What is happening?",options:["The train is cancelled","The train is delayed 20 min","The train is on time","The platform changed"],correctAnswer:"The train is delayed 20 min"}]},speaking:{summary:"Talk about travel experiences",exercises:[{id:"a2-ch1-c1-s1",title:"Trip Report",type:"prompt",prompt:"Tell your partner about a trip you took. Use passé composé: 'Je suis allé(e) à...', 'J'ai visité...', 'J'ai vu...'"},{id:"a2-ch1-c1-s2",title:"At the Ticket Office",type:"roleplay",prompt:"Roleplay buying a train ticket: ask for destination, departure time, price, and class."}]}}},{id:"a2-ch1-c2",title:"Décrire des vacances passées",description:"Describing past holidays and experiences",grammarFocus:"Passé composé with être (aller, venir, partir, arriver); Imparfait for descriptions",vocabularyTheme:"Holiday activities, weather, accommodations",skills:{reading:{summary:"Read holiday postcards and reviews",exercises:[{id:"a2-ch1-c2-r1",title:"Postcard",type:"comprehension",prompt:"Read: 'Cher Thomas, nous sommes à Nice. Le temps est magnifique. Hier, nous sommes allés à la plage et nous avons nagé. À bientôt, Julie.' What did Julie do yesterday?"},{id:"a2-ch1-c2-r2",title:"Hotel Review",type:"multiple-choice",prompt:"Read: 'L'hôtel était confortable. Le personnel était sympathique. La chambre était propre mais petite.' What was negative?",options:["Confortable","Sympathique","Propre","Petite"],correctAnswer:"Petite"}]},writing:{summary:"Write about holidays",exercises:[{id:"a2-ch1-c2-w1",title:"Holiday Postcard",type:"prompt",prompt:"Write a short postcard (4-5 sentences) to a friend describing your holiday, where you are, what the weather is like, and what you did yesterday."},{id:"a2-ch1-c2-w2",title:"Imparfait vs Passé Composé",type:"fill-blank",prompt:"Complete: 'Quand j'_____ (être) petit, nous _____ (aller) à la mer chaque été. L'année dernière, nous _____ (aller) en Grèce.'",correctAnswer:"étais; allions; sommes allés"}]},listening:{summary:"Understand holiday descriptions",exercises:[{id:"a2-ch1-c2-l1",title:"Holiday Stories",type:"comprehension",prompt:"You hear: 'L'été dernier, je suis partie en Espagne avec ma famille. Nous avons visité Barcelone et nous avons mangé des tapas.' Where did she go?"},{id:"a2-ch1-c2-l2",title:"Weather Report",type:"multiple-choice",prompt:"You hear: 'Pendant les vacances, il faisait beau et chaud. Nous avons passé des journées merveilleuses à la plage.' What was the weather like?",options:["Cold and rainy","Nice and hot","Windy","Cloudy"],correctAnswer:"Nice and hot"}]},speaking:{summary:"Describe past holidays",exercises:[{id:"a2-ch1-c2-s1",title:"Best Vacation",type:"prompt",prompt:"Describe your best holiday: where, when, with whom, what you did, the weather. Use passé composé and imparfait."},{id:"a2-ch1-c2-s2",title:"Compare Then and Now",type:"roleplay",prompt:"Compare holidays as a child (imparfait) with a recent holiday (passé composé): 'Quand j'étais jeune...', 'L'été dernier...'"}]}}}]},{id:"a2-ch2",title:"Santé et Bien-être",description:"Health, body, emotions, medical situations",concepts:[{id:"a2-ch2-c1",title:"Le corps et les sensations",description:"Describing physical sensations and health",grammarFocus:"Verb: avoir (mal à, faim, soif, chaud, froid); Reflexive verbs for daily care",vocabularyTheme:"Body parts, pain, symptoms, emotions",skills:{reading:{summary:"Read health advice and symptom descriptions",exercises:[{id:"a2-ch2-c1-r1",title:"Symptom Checker",type:"comprehension",prompt:"Read: 'J'ai mal à la tête et j'ai de la fièvre. Je tousse beaucoup.' What are the symptoms?",hint:"mal à la tête = headache, fièvre = fever, tousser = to cough"},{id:"a2-ch2-c1-r2",title:"Health Advice",type:"multiple-choice",prompt:"Read: 'Pour être en bonne santé, il faut boire beaucoup d'eau, manger équilibré et faire de l'exercice.' What is NOT mentioned?",options:["Drink water","Eat balanced meals","Take medicine","Exercise"],correctAnswer:"Take medicine"}]},writing:{summary:"Describe symptoms and feelings",exercises:[{id:"a2-ch2-c1-w1",title:"At the Doctor's",type:"prompt",prompt:"Write a short dialogue between a patient and a doctor describing 3 symptoms."},{id:"a2-ch2-c1-w2",title:"Emotions",type:"fill-blank",prompt:"Complete: 'Elle est _____ (happy). Nous sommes _____ (tired).'",correctAnswer:"heureuse; fatigués"}]},listening:{summary:"Understand health conversations",exercises:[{id:"a2-ch2-c1-l1",title:"Doctor's Consultation",type:"comprehension",prompt:"You hear: 'Depuis quand avez-vous mal à la gorge ? — Depuis trois jours. — Avez-vous de la fièvre ? — Oui, 38 degrés.' How long has the patient had a sore throat?"},{id:"a2-ch2-c1-l2",title:"How do they feel?",type:"multiple-choice",prompt:"You hear: 'Il a l'air fatigué. Il a mal dormi cette nuit.' How does he feel?",options:["Happy","Tired","Excited","Angry"],correctAnswer:"Tired"}]},speaking:{summary:"Describe health and feelings",exercises:[{id:"a2-ch2-c1-s1",title:"Doctor Roleplay",type:"roleplay",prompt:"Roleplay a doctor's visit: greet, describe symptoms ('J'ai mal à...'), answer questions, get advice."},{id:"a2-ch2-c1-s2",title:"How are you feeling?",type:"prompt",prompt:"Describe how you're feeling today using: 'Je suis...', 'J'ai...', 'Je me sens...'"}]}}}]},{id:"a2-ch3",title:"Culture et Loisirs",description:"Culture, hobbies, media, invitations",concepts:[{id:"a2-ch3-c1",title:"Les loisirs et les passions",description:"Hobbies, interests, making invitations",grammarFocus:"Verbs: pouvoir, devoir, savoir; Faire + activity; Invitations with vouloir + infinitive",vocabularyTheme:"Hobbies, sports, music, cinema",skills:{reading:{summary:"Read about hobbies and events",exercises:[{id:"a2-ch3-c1-r1",title:"Event Poster",type:"comprehension",prompt:"Read: 'Concert de musique classique – Samedi 20 mars à 20h – Salle Pleyel – 25€.' What type of event is it?"},{id:"a2-ch3-c1-r2",title:"Hobby Descriptions",type:"multiple-choice",prompt:"Read: 'Pendant mon temps libre, je fais du tennis et je joue de la guitare. J'aime aussi regarder des films.' What does NOT appear as a hobby?",options:["Tennis","Guitar","Reading","Movies"],correctAnswer:"Reading"}]},writing:{summary:"Write about hobbies and make invitations",exercises:[{id:"a2-ch3-c1-w1",title:"My Hobbies",type:"prompt",prompt:"Write 5 sentences about your hobbies: what you like to do, how often, since when."},{id:"a2-ch3-c1-w2",title:"Invitation",type:"prompt",prompt:"Write an invitation to a friend: suggest an activity, propose a time and place, ask if they want to come."}]},listening:{summary:"Understand discussions about hobbies",exercises:[{id:"a2-ch3-c1-l1",title:"Weekend Plans",type:"comprehension",prompt:"You hear: 'Ce week-end, je vais faire du vélo avec Paul, et dimanche, on va voir un film au cinéma.' What is the plan for Sunday?"},{id:"a2-ch3-c1-l2",title:"Invitation Response",type:"multiple-choice",prompt:"You invite: 'Tu veux venir au cinéma ?' Response: 'Avec plaisir ! On se retrouve à quelle heure ?'",options:["No, I'm busy","Yes, with pleasure","Maybe later","I don't like movies"],correctAnswer:"Yes, with pleasure"}]},speaking:{summary:"Talk about hobbies and make plans",exercises:[{id:"a2-ch3-c1-s1",title:"Free Time Chat",type:"roleplay",prompt:"Ask a friend about their hobbies: 'Qu'est-ce que tu aimes faire pendant ton temps libre ?', 'Tu fais du sport ?'"},{id:"a2-ch3-c1-s2",title:"Making Plans",type:"prompt",prompt:"Invite a friend to do something this weekend. Propose a time, day, and activity. Use 'Tu veux... ?', 'On pourrait...'"}]}}}]}]},i={id:"B1",title:"Intermediate – Indépendance",subtitle:"Threshold",description:"Can deal with most situations while travelling. Can produce simple connected text on topics that are familiar or of personal interest. Can describe experiences, events, dreams, hopes, and ambitions.",chapters:[{id:"b1-ch1",title:"Le Monde du Travail",description:"Work, careers, professional communication",concepts:[{id:"b1-ch1-c1",title:"Parler de son parcours professionnel",description:"Describing career paths, skills, and experience",grammarFocus:"Imparfait vs Passé Composé in narratives; Relative pronouns: qui, que",vocabularyTheme:"Professions, workplace, CV skills",skills:{reading:{summary:"Read job ads and applications",exercises:[{id:"b1-ch1-c1-r1",title:"Job Advertisement",type:"comprehension",prompt:"Read: 'Nous recherchons un développeur web qui a 3 ans d'expérience et qui parle anglais couramment. CDI à Paris. Salaire : 45k€.' What qualifications are required?",hint:"CDI = permanent contract"},{id:"b1-ch1-c1-r2",title:"Cover Letter Extract",type:"multiple-choice",prompt:"Read: 'Actuellement chargé de marketing chez TechCorp, je souhaiterais rejoindre votre équipe car je suis passionné par le secteur du e-commerce.' What is the person's current position?",options:["Marketing manager at TechCorp","Developer at TechCorp","CEO at TechCorp","Sales at TechCorp"],correctAnswer:"Marketing manager at TechCorp"}]},writing:{summary:"Write professional profiles and emails",exercises:[{id:"b1-ch1-c1-w1",title:"Professional Summary",type:"prompt",prompt:"Write a 5-sentence professional summary: your current role, past experience, skills, and career goals."},{id:"b1-ch1-c1-w2",title:"Job Application Email",type:"prompt",prompt:"Write a formal email applying for a job. Include: position you're applying for, your experience, why you're interested, and a request for an interview."}]},listening:{summary:"Understand professional discussions",exercises:[{id:"b1-ch1-c1-l1",title:"Job Interview",type:"comprehension",prompt:"You hear: 'Parlez-moi de votre expérience. — J'ai travaillé chez Dupont pendant 5 ans comme chef de projet. Ensuite, j'ai rejoint Martin SARL où je suis resté 3 ans.' How many years total experience?"},{id:"b1-ch1-c1-l2",title:"Meeting Discussion",type:"multiple-choice",prompt:"You hear: 'Nous devons finaliser le rapport avant vendredi. Sophie, vous pouvez vous en charger ? — Bien sûr, je m'en occupe.' Who is responsible for the report?",options:["The boss","Sophie","Nobody yet","The team"],correctAnswer:"Sophie"}]},speaking:{summary:"Talk about professional background",exercises:[{id:"b1-ch1-c1-s1",title:"Job Interview",type:"roleplay",prompt:"Roleplay a job interview: present your professional background, skills, and answer questions about your experience."},{id:"b1-ch1-c1-s2",title:"Elevator Pitch",type:"prompt",prompt:"Give a 1-minute professional pitch: who you are, what you do, your key achievements, and what you're looking for."}]}}},{id:"b1-ch1-c2",title:"Les réunions et la communication professionnelle",description:"Participating in meetings, professional correspondence",grammarFocus:"Conditionnel présent (je voudrais, on pourrait); Subordonnées avec si",vocabularyTheme:"Business meetings, proposals, negotiations",skills:{reading:{summary:"Read meeting agendas and professional emails",exercises:[{id:"b1-ch1-c2-r1",title:"Meeting Agenda",type:"comprehension",prompt:"Read: 'Ordre du jour: 1. Bilan Q3, 2. Nouveau projet client, 3. Budget 2026.' What is the third point on the agenda?"},{id:"b1-ch1-c2-r2",title:"Professional Email",type:"multiple-choice",prompt:"Read: 'Suite à notre conversation téléphonique, je vous confirme notre rendez-vous du 15 mars à 14h dans nos bureaux.' What is the email about?",options:["Cancelling a meeting","Confirming a meeting","Rescheduling","Complaint"],correctAnswer:"Confirming a meeting"}]},writing:{summary:"Write professional correspondence",exercises:[{id:"b1-ch1-c2-w1",title:"Meeting Minutes",type:"prompt",prompt:"Write meeting minutes for a team meeting: date, attendees, key discussion points, and action items."},{id:"b1-ch1-c2-w2",title:"Proposal Email",type:"prompt",prompt:"Write a professional email proposing a new idea. Use conditionnel: 'Je voudrais proposer...', 'Nous pourrions...'"}]},listening:{summary:"Understand meetings and discussions",exercises:[{id:"b1-ch1-c2-l1",title:"Meeting Discussion",type:"comprehension",prompt:"You hear: 'Si nous augmentons le budget marketing de 15 %, nous pourrions atteindre 20 % de clients en plus. Qu'en pensez-vous ?' What is the proposal?"},{id:"b1-ch1-c2-l2",title:"Opinions",type:"multiple-choice",prompt:"You hear: 'À mon avis, ce n'est pas la meilleure solution. Je pense que nous devrions envisager d'autres options.' What does the speaker express?",options:["Agreement","Disagreement","Certainty","Confusion"],correctAnswer:"Disagreement"}]},speaking:{summary:"Participate in professional discussions",exercises:[{id:"b1-ch1-c2-s1",title:"Team Meeting",type:"roleplay",prompt:"Participate in a team meeting: give your opinion, agree/disagree politely, make suggestions using conditionnel."},{id:"b1-ch1-c2-s2",title:"Persuasive Pitch",type:"prompt",prompt:"Pitch an idea to your team: describe the idea, explain why it's beneficial, and ask for feedback."}]}}}]},{id:"b1-ch2",title:"Médias et Société",description:"News, social issues, expressing opinions",concepts:[{id:"b1-ch2-c1",title:"L'actualité et les médias",description:"Discussing news, understanding media",grammarFocus:"Passive voice; Present subjunctive (il faut que, bien que)",vocabularyTheme:"News, media, current events, environment",skills:{reading:{summary:"Read news articles and opinion pieces",exercises:[{id:"b1-ch2-c1-r1",title:"News Headline",type:"comprehension",prompt:"Read: 'Le gouvernement annonce un nouveau plan pour réduire la pollution dans les grandes villes à partir de 2026.' What is the government's plan about?",hint:"Réduire la pollution = reduce pollution"},{id:"b1-ch2-c1-r2",title:"Opinion Editorial",type:"multiple-choice",prompt:"Read: 'Selon le ministre, il est essentiel que nous investissions dans les énergies renouvelables. Bien que cela coûte cher à court terme, les bénéfices à long terme sont évidents.' What is the minister's position?",options:["Against renewable energy","Supportive of renewable energy","Neutral","Undecided"],correctAnswer:"Supportive of renewable energy"}]},writing:{summary:"Write opinions and summaries",exercises:[{id:"b1-ch2-c1-w1",title:"News Summary",type:"prompt",prompt:"Write a 5-sentence summary of a recent news event. Include: what happened, when, who was involved, and your opinion."},{id:"b1-ch2-c1-w2",title:"Letter to the Editor",type:"prompt",prompt:"Write a letter to the editor expressing your opinion on an environmental issue. Use subjunctive: 'Il est important que...', 'Je pense qu'il faut que...'"}]},listening:{summary:"Understand news reports and discussions",exercises:[{id:"b1-ch2-c1-l1",title:"News Report",type:"comprehension",prompt:"You hear: 'Un séisme de magnitude 6,2 a frappé la région ce matin à 8h15. Les secours sont déjà sur place. Il n'y a pas de victimes pour le moment.' What happened and when?"},{id:"b1-ch2-c1-l2",title:"Radio Discussion",type:"multiple-choice",prompt:"You hear two people debating: 'Je ne suis pas d'accord. Bien que les réseaux sociaux aient des avantages, ils présentent aussi des risques pour la vie privée.' What is the speaker doing?",options:["Agreeing","Disagreeing and giving reasons","Asking a question","Changing the subject"],correctAnswer:"Disagreeing and giving reasons"}]},speaking:{summary:"Discuss news and express opinions",exercises:[{id:"b1-ch2-c1-s1",title:"News Debate",type:"roleplay",prompt:"Discuss a current news topic with a partner: state your opinion, respond to counterarguments, use expressions like 'À mon avis...', 'Je pense que...', 'Tu as raison mais...'"},{id:"b1-ch2-c1-s2",title:"Present a Topic",type:"prompt",prompt:"Present a news topic for 2 minutes: introduce the topic, give facts, express your opinion, and conclude."}]}}}]}]},r={id:"B2",title:"Upper-Intermediate – Autonomie",subtitle:"Vantage",description:"Can understand the main ideas of complex text. Can interact with a degree of fluency and spontaneity. Can produce clear, detailed text on a wide range of subjects.",chapters:[{id:"b2-ch1",title:"Communication Avancée",description:"Nuanced expression, argumentation, debate",concepts:[{id:"b2-ch1-c1",title:"L'argumentation et le débat",description:"Structuring arguments, debating, persuasive language",grammarFocus:"Subjunctive vs indicative; Concessive expressions (bien que, malgré, quoique)",vocabularyTheme:"Debate, persuasion, rhetoric, current issues",skills:{reading:{summary:"Read complex argumentative texts",exercises:[{id:"b2-ch1-c1-r1",title:"Argumentative Essay",type:"comprehension",prompt:"Read: 'Bien que le télétravail présente des avantages indéniables en termes de flexibilité, il convient de s'interroger sur ses effets à long terme concernant la cohésion d'équipe et l'innovation collective.' What is the author's main concern about remote work?",hint:"Cohésion d'équipe = team cohesion"},{id:"b2-ch1-c1-r2",title:"Identify the Argument",type:"multiple-choice",prompt:"Read: 'Si l'on considère les données économiques, force est de constater que l'investissement dans les énergies vertes est non seulement bénéfique pour l'environnement mais également rentable à moyen terme.' What type of argument is this?",options:["Environmental only","Economic only","Both environmental and economic","Neither"],correctAnswer:"Both environmental and economic"}]},writing:{summary:"Write argumentative texts and essays",exercises:[{id:"b2-ch1-c1-w1",title:"For and Against",type:"prompt",prompt:"Write a balanced argument (200 words) on: 'Les réseaux sociaux : avantages et inconvénients.' Present both sides and conclude."},{id:"b2-ch1-c1-w2",title:"Subjunctive Practice",type:"fill-blank",prompt:"Complete: 'Bien qu'il _____ (être) en retard, nous avons attendu. Il faut que tu _____ (venir) à la réunion.'",correctAnswer:"soit; viennes"}]},listening:{summary:"Understand debates and complex discussions",exercises:[{id:"b2-ch1-c1-l1",title:"Debate Analysis",type:"comprehension",prompt:"You hear: 'Le premier argument en faveur de cette réforme est économique. Cependant, on ne peut ignorer les conséquences sociales. D'autre part, les opposants soulèvent des questions légitimes concernant la faisabilité.' Summarise the positions mentioned."},{id:"b2-ch1-c1-l2",title:"Nuanced Position",type:"multiple-choice",prompt:"You hear: 'Je comprends parfaitement ton point de vue, et sur certains aspects tu as tout à fait raison. Néanmoins, je pense qu'il faut aussi considérer le contexte social plus large.' What is the speaker doing?",options:["Totally agreeing","Totally disagreeing","Partially agreeing","Changing the subject"],correctAnswer:"Partially agreeing"}]},speaking:{summary:"Debate and express nuanced opinions",exercises:[{id:"b2-ch1-c1-s1",title:"Structured Debate",type:"roleplay",prompt:"Debate: 'Le télétravail devrait être obligatoire.' One person argues for, the other against. Use: 'D'une part... d'autre part...', 'Cependant...', 'En conclusion...'"},{id:"b2-ch1-c1-s2",title:"Nuanced Opinion",type:"prompt",prompt:"Give a 3-minute opinion on a controversial topic. Include concessions, counterarguments, and a balanced conclusion."}]}}},{id:"b2-ch1-c2",title:"Le français formel et informel",description:"Register switching: formal vs informal French, registers of speech",grammarFocus:"Pronoms relatifs composés (lequel, auquel, duquel); Plus-que-parfait",vocabularyTheme:"Formal correspondence, colloquial expressions, slang",skills:{reading:{summary:"Distinguish formal and informal texts",exercises:[{id:"b2-ch1-c2-r1",title:"Formal vs Informal",type:"comprehension",prompt:"Compare: 'Salut mec, ça roule ?' and 'Bonjour Monsieur, comment allez-vous ?' Identify the register and appropriate context for each."},{id:"b2-ch1-c2-r2",title:"Administrative Document",type:"multiple-choice",prompt:"Read: 'Veuillez trouver ci-joint les documents relatifs à votre demande de remboursement, que nous avons traitée en date du 15 courant.' What is this text?",options:["A personal letter","An administrative email","A text message","A news article"],correctAnswer:"An administrative email"}]},writing:{summary:"Adapt writing to appropriate register",exercises:[{id:"b2-ch1-c2-w1",title:"Register Adaptation",type:"prompt",prompt:"Rewrite this informal message in formal register: 'Salut ! Dis donc, tu peux me filer le rapport ? Merci, à plus !'"},{id:"b2-ch1-c2-w2",title:"Relative Pronouns",type:"fill-blank",prompt:"Complete: 'C'est l'entreprise pour _____ (which) je travaille. Voici le projet _____ (which) je t'ai parlé.'",correctAnswer:"laquelle; dont"}]},listening:{summary:"Recognise register in spoken French",exercises:[{id:"b2-ch1-c2-l1",title:"Register Recognition",type:"comprehension",prompt:"You hear: 'Excusez-moi de vous déranger, auriez-vous un instant pour discuter du dossier ?' and 'Hé, t'as cinq minutes pour parler du truc ?' Identify the register of each and the relationship between speakers."},{id:"b2-ch1-c2-l2",title:"Context Match",type:"multiple-choice",prompt:"You hear: 'Je vous prie d'agréer, Monsieur, l'expression de mes salutations distinguées.' Where would you most likely hear this?",options:["At a party","In a formal letter closing","On the phone with a friend","In a restaurant"],correctAnswer:"In a formal letter closing"}]},speaking:{summary:"Switch between formal and informal registers",exercises:[{id:"b2-ch1-c2-s1",title:"Register Switching",type:"roleplay",prompt:"Roleplay the same scenario (asking for a favour) twice: once with a close friend (informal), once with your boss (formal)."},{id:"b2-ch1-c2-s2",title:"Professional Phone Call",type:"prompt",prompt:"Make a formal phone call to a client: introduce yourself, state your purpose, confirm details, and close politely."}]}}}]},{id:"b2-ch2",title:"Littérature et Arts",description:"Literary analysis, artistic expression, cultural criticism",concepts:[{id:"b2-ch2-c1",title:"Analyser un texte littéraire",description:"Reading and analyzing French literature",grammarFocus:"Literary tenses (passé simple); Hypothetical structures (si + plus-que-parfait + conditionnel passé)",vocabularyTheme:"Literary analysis, genres, literary terms",skills:{reading:{summary:"Read and analyze literary excerpts",exercises:[{id:"b2-ch2-c1-r1",title:"Literary Extract Analysis",type:"comprehension",prompt:"Read the extract from Camus: 'Aujourd'hui, maman est morte. Ou peut-être hier, je ne sais pas.' Analyse the tone, narrator's state of mind, and narrative technique."},{id:"b2-ch2-c1-r2",title:"Identify the Genre",type:"multiple-choice",prompt:"Read: 'Il était une fois, dans un royaume lointain, un roi et une reine qui vivaient heureux dans leur château.' What genre is this?",options:["Poetry","Fairy tale","News article","Scientific text"],correctAnswer:"Fairy tale"}]},writing:{summary:"Write literary analyses and creative texts",exercises:[{id:"b2-ch2-c1-w1",title:"Literary Analysis",type:"prompt",prompt:"Write a 250-word analysis of a short literary extract. Discuss theme, style, tone, and literary devices."},{id:"b2-ch2-c1-w2",title:"Creative Writing",type:"prompt",prompt:"Write a short story (200 words) starting with: 'Il était une fois...' Use passé simple for narrative events."}]},listening:{summary:"Understand literary discussions and readings",exercises:[{id:"b2-ch2-c1-l1",title:"Author Interview",type:"comprehension",prompt:"You hear: 'Dans mon dernier roman, j'ai voulu explorer la question de l'identité à travers le regard d'un personnage qui perd la mémoire.' What is the book about?"},{id:"b2-ch2-c1-l2",title:"Poetry Reading",type:"dictation",prompt:"Listen to the poem reading and write down the first stanza you hear."}]},speaking:{summary:"Discuss literature and express analysis",exercises:[{id:"b2-ch2-c1-s1",title:"Book Discussion",type:"roleplay",prompt:"Discuss a book you've read: present the author, plot summary, themes, and your personal opinion. Respond to your partner's questions."},{id:"b2-ch2-c1-s2",title:"Literary Critique",type:"prompt",prompt:"Present a 3-minute critique of a work of French literature or film. Analyze style, themes, and cultural significance."}]}}}]}]},s={id:"C1",title:"Advanced – Maîtrise",subtitle:"Effective Operational Proficiency",description:"Can understand a wide range of demanding, longer texts. Can express ideas fluently and spontaneously without much searching for expressions. Can use language flexibly for social, academic, and professional purposes.",chapters:[{id:"c1-ch1",title:"Discours Académique et Professionnel",description:"Academic writing, presentations, high-level professional communication",concepts:[{id:"c1-ch1-c1",title:"La synthèse de documents",description:"Summarizing and synthesising multiple sources",grammarFocus:"Nominalization; Complex relative structures; Gérondif",vocabularyTheme:"Academic vocabulary, discourse markers, transition words",skills:{reading:{summary:"Read multiple sources and identify key points",exercises:[{id:"c1-ch1-c1-r1",title:"Comparative Analysis",type:"comprehension",prompt:"Read two short texts on climate policy. Text A argues for carbon taxes. Text B advocates for technological solutions. Identify the main arguments of each and the points of disagreement.",hint:"Look for opinion markers and contrasting viewpoints"},{id:"c1-ch1-c1-r2",title:"Abstract Extraction",type:"short-answer",prompt:"Read this academic abstract and identify: research question, methodology, findings, and conclusion in your own words."}]},writing:{summary:"Write syntheses and academic documents",exercises:[{id:"c1-ch1-c1-w1",title:"Document Synthesis",type:"prompt",prompt:"Write a 300-word synthesis of three documents with different perspectives on the same topic. Structure: introduction, thematic comparison, conclusion."},{id:"c1-ch1-c1-w2",title:"Nominalization Exercise",type:"fill-blank",prompt:"Transform: 'Le gouvernement a décidé d'augmenter les impôts' → 'La _____ des impôts par le gouvernement.'",correctAnswer:"décision d'augmentation"}]},listening:{summary:"Understand complex academic presentations",exercises:[{id:"c1-ch1-c1-l1",title:"Conference Talk",type:"comprehension",prompt:"You hear a 3-minute academic presentation. Identify: the research problem, methodology, key findings, and the speaker's conclusion."},{id:"c1-ch1-c1-l2",title:"Q&A Session",type:"multiple-choice",prompt:"You hear: 'Pourriez-vous préciser comment votre étude contrôle les variables confondantes ?' What is the questioner asking about?",options:["The conclusion","The methodology","The funding","The publication date"],correctAnswer:"The methodology"}]},speaking:{summary:"Deliver academic presentations and discussions",exercises:[{id:"c1-ch1-c1-s1",title:"Academic Presentation",type:"prompt",prompt:"Deliver a 5-minute academic presentation on a topic of your choice. Structure: introduction, background, main argument, evidence, conclusion. Use discourse markers."},{id:"c1-ch1-c1-s2",title:"Seminar Discussion",type:"roleplay",prompt:"Participate in a seminar discussion: respond to questions, challenge ideas respectfully, build on others' points using complex connectors."}]}}},{id:"c1-ch1-c2",title:"La langue des médias spécialisés",description:"Understanding specialized media (science, law, finance)",grammarFocus:"Subjonctif passé; Conditional past; Passive constructions",vocabularyTheme:"Legal, financial, scientific terminology",skills:{reading:{summary:"Read specialized articles",exercises:[{id:"c1-ch1-c2-r1",title:"Scientific Article",type:"comprehension",prompt:"Read this scientific abstract in French. Identify: hypothesis, methodology, sample size, results, and limitations."},{id:"c1-ch1-c2-r2",title:"Legal Text",type:"multiple-choice",prompt:"Read: 'Aux termes de l'article L. 121-1 du Code du travail, l'employeur est tenu d'assurer la sécurité de ses salariés.' What does this article establish?",options:["Employee rights","Employer obligation for safety","Work schedule","Salary requirements"],correctAnswer:"Employer obligation for safety"}]},writing:{summary:"Write specialized content",exercises:[{id:"c1-ch1-c2-w1",title:"Technical Report",type:"prompt",prompt:"Write a 300-word technical report in your field of expertise. Use appropriate jargon, passive constructions, and precise data."},{id:"c1-ch1-c2-w2",title:"Subjunctive Past",type:"fill-blank",prompt:"Complete: 'Bien qu'il _____ (faire) toutes ses recherches, la commission n'a pas été convaincue.'",correctAnswer:"ait fait"}]},listening:{summary:"Understand specialized presentations",exercises:[{id:"c1-ch1-c2-l1",title:"Expert Interview",type:"comprehension",prompt:"You hear a financial analyst discussing market trends. Identify the sectors mentioned, the predicted trends, and the supporting evidence provided."},{id:"c1-ch1-c2-l2",title:"Scientific Lecture",type:"dictation",prompt:"Listen to the lecture excerpt and transcribe the key methodological explanation. Note specialized terminology."}]},speaking:{summary:"Discuss specialized topics",exercises:[{id:"c1-ch1-c2-s1",title:"Expert Roundtable",type:"roleplay",prompt:"Participate in a roundtable discussion on a specialized topic. Present your expert opinion, respond to questions, and engage with others' viewpoints."},{id:"c1-ch1-c2-s2",title:"Explain a Concept",type:"prompt",prompt:"Explain a complex concept from your field to both an expert audience (3 min) and a general audience (2 min), adapting your language register."}]}}}]},{id:"c1-ch2",title:"Nuances et Subtilités",description:"Nuance, humor, idiomatic mastery, cultural references",concepts:[{id:"c1-ch2-c1",title:"L'humour et l'ironie",description:"Understanding and using humor, irony, and satire",grammarFocus:"Mise en relief (c'est... qui/que); Exclamatory structures",vocabularyTheme:"Humor, irony, wordplay, cultural references",skills:{reading:{summary:"Read satire and humorous texts",exercises:[{id:"c1-ch2-c1-r1",title:"Satirical Article",type:"comprehension",prompt:"Read: 'Le gouvernement a enfin trouvé la solution miracle au chômage : il suffit de ne plus compter les chômeurs. Une idée tellement simple qu'on se demande pourquoi personne n'y a pensé plus tôt.' Identify the use of irony and explain the real critique."},{id:"c1-ch2-c1-r2",title:"Wordplay Analysis",type:"short-answer",prompt:"Analyse the pun: 'Pourquoi les plongeurs plongent-ils en arrière ? Parce que sinon ils tombent dans le bateau.' Explain the wordplay mechanism."}]},writing:{summary:"Write humorous and ironic texts",exercises:[{id:"c1-ch2-c1-w1",title:"Satirical Piece",type:"prompt",prompt:"Write a short satirical piece (200 words) on a current topic. Use irony, exaggeration, and wit to make your point."},{id:"c1-ch2-c1-w2",title:"Mise en Relief",type:"fill-blank",prompt:"Transform: 'Pierre a volé la vedette.' → 'C'est _____ qui a volé la vedette.'",correctAnswer:"Pierre"}]},listening:{summary:"Recognize irony and humor in speech",exercises:[{id:"c1-ch2-c1-l1",title:"Comedy Sketch",type:"comprehension",prompt:"Listen to a French comedy sketch. Identify: the humorous devices used (exaggeration, irony, wordplay), the target of the humor, and why it's funny."},{id:"c1-ch2-c1-l2",title:"Tone Recognition",type:"multiple-choice",prompt:"You hear: 'Ah, magnifique ! Il pleut encore. Exactement ce qu'il nous fallait pour le pique-nique.' What is the tone?",options:["Genuine enthusiasm","Sarcasm/irony","Sadness","Confusion"],correctAnswer:"Sarcasm/irony"}]},speaking:{summary:"Use humor and irony appropriately",exercises:[{id:"c1-ch2-c1-s1",title:"Tell a Funny Story",type:"prompt",prompt:"Tell a funny anecdote in French. Use appropriate timing, exaggeration, and punchline delivery."},{id:"c1-ch2-c1-s2",title:"Irony Practice",type:"roleplay",prompt:"React to these situations with ironic comments: your train is cancelled, you spill coffee, it rains on your day off."}]}}},{id:"c1-ch2-c2",title:"Expressions idiomatiques et proverbes",description:"Mastering idioms, proverbs, and fixed expressions",grammarFocus:"Fixed expressions; Figurative language; Register variation",vocabularyTheme:"Idioms, proverbs, fixed expressions, cultural sayings",skills:{reading:{summary:"Recognize and interpret idioms in context",exercises:[{id:"c1-ch2-c2-r1",title:"Idiom Hunt",type:"comprehension",prompt:"Read: 'Quand le chat n'est pas là, les souris dansent. C'est exactement ce qui se passe au bureau quand le patron est en vacances.' Explain the idiom and how it applies to the situation."},{id:"c1-ch2-c2-r2",title:"Proverb Matching",type:"match",prompt:"Match each French proverb to its equivalent meaning: 'Qui vivra verra', 'Petit à petit, l'oiseau fait son nid', 'Après la pluie, le beau temps'"}]},writing:{summary:"Write using idiomatic expressions",exercises:[{id:"c1-ch2-c2-w1",title:"Idiom Story",type:"prompt",prompt:"Write a short story (200 words) that incorporates at least 5 French idiomatic expressions naturally. Underline each idiom used."},{id:"c1-ch2-c2-w2",title:"Proverb Application",type:"short-answer",prompt:"Choose a situation and write how you would use the proverb: 'Mieux vaut tard que jamais' appropriately."}]},listening:{summary:"Recognize idioms in spoken French",exercises:[{id:"c1-ch2-c2-l1",title:"Idiom Recognition",type:"comprehension",prompt:"Listen to these short dialogues and identify the idiomatic expression used in each. Explain its meaning."},{id:"c1-ch2-c2-l2",title:"Context Clues",type:"multiple-choice",prompt:"You hear: 'Ne cherche pas midi à quatorze heures, la réponse est simple.' What does the speaker mean?",options:["Look for the easy answer","Don't overcomplicate things","Check the time","Wait until noon"],correctAnswer:"Don't overcomplicate things"}]},speaking:{summary:"Use idioms naturally in conversation",exercises:[{id:"c1-ch2-c2-s1",title:"Idiom Conversation",type:"roleplay",prompt:"Have a conversation where you naturally use at least 3 idioms. Your partner will try to identify them."},{id:"c1-ch2-c2-s2",title:"Explain an Idiom",type:"prompt",prompt:"Choose a French idiom, explain its literal meaning, its actual meaning, and give an example of when to use it."}]}}}]}]},a={id:"C2",title:"Mastery – Perfectionnement",subtitle:"Mastery",description:"Can understand with ease virtually everything heard or read. Can summarise information from different spoken and written sources. Can express themselves spontaneously, very fluently and precisely, differentiating finer shades of meaning.",chapters:[{id:"c2-ch1",title:"Maîtrise Stylistique",description:"Stylistic mastery, rhetorical devices, advanced writing",concepts:[{id:"c2-ch1-c1",title:"Les figures de style avancées",description:"Advanced rhetorical figures and stylistic devices",grammarFocus:"All stylistic registers; Anaphora, chiasmus, litotes, hyperbole",vocabularyTheme:"Rhetoric, stylistic analysis, literary devices",skills:{reading:{summary:"Analyse advanced literary and rhetorical texts",exercises:[{id:"c2-ch1-c1-r1",title:"Rhetorical Analysis",type:"comprehension",prompt:"Read the passage from a political speech. Identify and analyse: anaphora, metaphor, parallelism, and the overall rhetorical strategy.",hint:"Look for repetition patterns, comparisons, and structural balance"},{id:"c2-ch1-c1-r2",title:"Stylistic Identification",type:"multiple-choice",prompt:"Read: 'Va, je ne te hais point.' (Corneille) What figure of speech is used here?",options:["Hyperbole","Litotes","Metaphor","Anaphora"],correctAnswer:"Litotes"}]},writing:{summary:"Write using advanced stylistic devices",exercises:[{id:"c2-ch1-c1-w1",title:"Stylistic Imitation",type:"prompt",prompt:"Write a paragraph (200 words) imitating the style of a specific French author (Proust, Camus, Duras). Focus on sentence structure, rhythm, and vocabulary choices."},{id:"c2-ch1-c1-w2",title:"Rhetorical Speech",type:"prompt",prompt:"Write a persuasive speech (400 words) using at least 5 different rhetorical devices. Annotate your speech identifying each device."}]},listening:{summary:"Recognize sophisticated rhetorical techniques",exercises:[{id:"c2-ch1-c1-l1",title:"Speech Analysis",type:"comprehension",prompt:"Listen to a French political speech. Identify the rhetorical devices used (anaphora, tricolon, contrast, metaphor) and analyse their effect on the audience."},{id:"c2-ch1-c1-l2",title:"Stylistic Variation",type:"short-answer",prompt:"Listen to three speakers discussing the same topic. Compare their stylistic approaches, register choices, and rhetorical strategies."}]},speaking:{summary:"Speak using advanced rhetorical techniques",exercises:[{id:"c2-ch1-c1-s1",title:"Rhetorical Speech",type:"prompt",prompt:"Deliver a 5-minute persuasive speech on a topic of your choice. Use rhetorical devices: anaphora, rhetorical questions, tricolon, and antithesis."},{id:"c2-ch1-c1-s2",title:"Impromptu Style",type:"roleplay",prompt:"Given a random topic, speak for 3 minutes using a specific rhetorical device (e.g., 'Speak only using metaphors')."}]}}},{id:"c2-ch1-c2",title:"La traduction et l'adaptation",description:"Advanced translation, adaptation between registers and contexts",grammarFocus:"Grammatical transposition; Calque awareness; False friends mastery",vocabularyTheme:"Translation theory, adaptation, localization",skills:{reading:{summary:"Analyse translations and adaptations",exercises:[{id:"c2-ch1-c2-r1",title:"Translation Comparison",type:"comprehension",prompt:"Read three different French translations of the same Shakespeare sonnet. Compare: fidelity to original, poetic choices, and cultural adaptation."},{id:"c2-ch1-c2-r2",title:"False Friends Alert",type:"multiple-choice",prompt:"Which of these is a faux-ami for the English word 'actually'?",options:["actuellement","réellement","vraiment","maintenant"],correctAnswer:"actuellement"}]},writing:{summary:"Translate and adapt texts",exercises:[{id:"c2-ch1-c2-w1",title:"Literary Translation",type:"prompt",prompt:"Translate an English literary passage into French (300 words). Justify your key choices: register, cultural adaptation, idiomatic equivalents."},{id:"c2-ch1-c2-w2",title:"Register Adaptation",type:"prompt",prompt:"Adapt this formal legal text into clear French for a general audience. Maintain accuracy while making it accessible."}]},listening:{summary:"Understand subtleties in different varieties of French",exercises:[{id:"c2-ch1-c2-l1",title:"Regional Variety Recognition",type:"comprehension",prompt:"Listen to speakers from France, Québec, Belgium, and Switzerland. Identify: phonetic differences, vocabulary variations, and unique expressions from each region."},{id:"c2-ch1-c2-l2",title:"Simultaneous Interpretation",type:"dictation",prompt:"Listen to a short speech and simultaneously interpret it into English, then compare your version with a professional interpretation."}]},speaking:{summary:"Adapt speech across varieties and contexts",exercises:[{id:"c2-ch1-c2-s1",title:"Accent Adaptation",type:"prompt",prompt:"Read the same passage with a standard French accent, then with a Québécois accent, adapting vocabulary and pronunciation appropriately."},{id:"c2-ch1-c2-s2",title:"Consecutive Interpretation",type:"roleplay",prompt:"Interpret a conversation between a French speaker and an English speaker, handling nuance, cultural references, and register appropriately."}]}}}]},{id:"c2-ch2",title:"Discours Critique et Expertise",description:"Critical discourse, expertise, research-level French",concepts:[{id:"c2-ch2-c1",title:"La critique et l'expertise",description:"Expert-level critique, evaluation, and scholarly discourse",grammarFocus:"All grammar points integrated; Absolute constructions; Infinitive past",vocabularyTheme:"Critique, evaluation, scholarly terminology",skills:{reading:{summary:"Read and critique expert-level texts",exercises:[{id:"c2-ch2-c1-r1",title:"Critical Review",type:"comprehension",prompt:"Read this scholarly article and write a critical review: identify the thesis, evaluate the methodology, assess the evidence, note any biases, and suggest improvements."},{id:"c2-ch2-c1-r2",title:"Comparative Critique",type:"short-answer",prompt:"Compare two competing theories presented in these texts. Evaluate their strengths and weaknesses, and take a position with justification."}]},writing:{summary:"Write expert-level critiques",exercises:[{id:"c2-ch2-c1-w1",title:"Academic Peer Review",type:"prompt",prompt:"Write a peer review (500 words) of an academic article. Structure: summary, strengths, weaknesses, specific suggestions, recommendation."},{id:"c2-ch2-c1-w2",title:"Expert Opinion Piece",type:"prompt",prompt:"Write an expert opinion piece (500 words) for a major French newspaper on a topic in your field. Command authority while remaining accessible to educated readers."}]},listening:{summary:"Understand expert-level discourse",exercises:[{id:"c2-ch2-c1-l1",title:"Expert Panel",type:"comprehension",prompt:"Listen to an expert panel discussion. Summarise each expert's position, identify points of agreement and disagreement, and evaluate the strength of their arguments."},{id:"c2-ch2-c1-l2",title:"PhD Defense",type:"comprehension",prompt:"Listen to excerpts from a PhD defense. Identify: the thesis statement, methodology, key findings, and the committee's critiques."}]},speaking:{summary:"Engage in expert-level discussions",exercises:[{id:"c2-ch2-c1-s1",title:"Expert Conference Panel",type:"roleplay",prompt:"Participate in a conference panel discussion. Present your research, respond to questions from the audience, and engage with fellow panelists."},{id:"c2-ch2-c1-s2",title:"Defend a Position",type:"prompt",prompt:"Present and defend a controversial position in your field (8 minutes). Anticipate counterarguments, address them, and conclude compellingly."}]}}}]}]},o={A1:e,A2:t,B1:i,B2:r,C1:s,C2:a},n=["A1","A2","B1","B2","C1","C2"];export{o as a,n as c};
